-- 4. Notificações de usuários de teste
DELETE FROM notifications WHERE userId IN (SELECT id FROM users WHERE email LIKE '%@test.com');

-- 5. Referrals de usuários de teste
DELETE FROM referrals WHERE referrerId IN (SELECT id FROM users WHERE email LIKE '%@test.com') OR referredId IN (SELECT id FROM users WHERE email LIKE '%@test.com');

-- 6. Push subscriptions de usuários de teste
DELETE FROM push_subscriptions WHERE userId IN (SELECT id FROM users WHERE email LIKE '%@test.com');

-- 7. User plans de usuários de teste
DELETE FROM user_plans WHERE userId IN (SELECT id FROM users WHERE email LIKE '%@test.com');

-- 8. Pool scoring rules de bolões de teste
DELETE FROM pool_scoring_rules WHERE poolId IN (SELECT id FROM pools WHERE name LIKE '%teste%' OR name LIKE '%Teste%' OR name LIKE 'it%');

-- 9. Pool member stats de bolões de teste
DELETE FROM pool_member_stats WHERE poolId IN (SELECT id FROM pools WHERE name LIKE '%teste%' OR name LIKE '%Teste%' OR name LIKE 'it%');

