-- 11. Bets vinculados a bolões de teste
DELETE FROM bets WHERE poolId IN (SELECT id FROM pools WHERE name LIKE '%teste%' OR name LIKE '%Teste%' OR name LIKE 'it%');

-- 12. Pool members de bolões de teste
